```class Solution {
    public long smallestNumber(long num) {
        if (num == 0) {
            return 0;
        }
        String str = String.valueOf(Math.abs(num));
        char[] arr = str.toCharArray();
        Arrays.sort(arr);
        if (arr[0] == '0') {
            for (int i = 1; i < arr.length; i++) {
                if (arr[i] != '0') {
                    char temp = arr[0];
                    arr[0] = arr[i];
                    arr[i] = temp;
                    break;
                }
            }
        }
        return Long.parseLong(new String(arr));
    }
}```
